// Check if today is a rest day (configurable)
// Default rest day: Saturday (day 6 in JS Date)
// Configurable via REST_DAYS array below

const REST_DAYS = [6]; // 0=Sunday, 1=Monday, ..., 6=Saturday

// Get current day in Asia/Jerusalem timezone
const now = new Date();
const jerusalemTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Jerusalem' }));
const dayOfWeek = jerusalemTime.getDay();

if (REST_DAYS.includes(dayOfWeek)) {
  console.log('Today is a rest day (day ' + dayOfWeek + ') — skipping cutoff alert');
  return [{ json: { skip: true, reason: 'rest_day', day_of_week: dayOfWeek } }];
}

return [{ json: { skip: false, day_of_week: dayOfWeek } }];

// Check Today's Records — query Supabase for attendance_logs count today
// Uses Asia/Jerusalem timezone to determine 'today'
// AC4: check if zero records written for current calendar day

const SUPABASE_URL = 'https://jnsfklshpabogzvolzct.supabase.co/rest/v1/attendance_logs';
const SERVICE_KEY = '<SUPABASE_SERVICE_ROLE_KEY>';

// Get today's date in Asia/Jerusalem timezone
const now = new Date();
const jerusalemDate = now.toLocaleDateString('en-CA', { timeZone: 'Asia/Jerusalem' }); // YYYY-MM-DD format

try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '?select=id&work_date=eq.' + jerusalemDate,
    headers: {
      'apikey': SERVICE_KEY,
      'Authorization': 'Bearer ' + SERVICE_KEY,
      'Prefer': 'count=exact',
    },
    returnFullResponse: true,
    json: true,
  });

  // PostgREST returns count in content-range header when Prefer: count=exact is set
  const contentRange = response.headers['content-range'] || '';
  const countMatch = contentRange.match(/\/(\d+)$/);
  const count = countMatch ? parseInt(countMatch[1], 10) : (Array.isArray(response.body) ? response.body.length : 0);

  console.log('Attendance records for ' + jerusalemDate + ': ' + count);
  return [{ json: { count: count, date: jerusalemDate } }];
} catch (error) {
  console.log('Failed to check attendance records: ' + error.message);
  // On error, send the alert anyway — better a false positive than missing a real empty day
  return [{ json: { count: 0, date: jerusalemDate, check_error: error.message } }];
}

